import{_ as u}from"./plugin-vue_export-helper-DlAUqK2U.js";import{aj as h,am as s,as as m,ao as a,at as l,au as c,ap as t,al as k,ak as v,aq as i,ar as g,an as o}from"./app-gTf-Epb-.js";const b={},y={id:"frontmatter-title-관련",tabindex:"-1"},f={class:"header-anchor",href:"#frontmatter-title-관련"},w={class:"table-of-contents"};function x(r,n){const p=i("VPCard"),e=i("router-link"),d=i("SiteInfo");return g(),h("div",null,[s("h1",y,[s("a",f,[s("span",null,m(r.$frontmatter.title)+" 관련",1)])]),a(p,l(c({title:" > Article(s)",desc:"Article(s)",link:"/programming/cs/articles/README.md",logo:"https://chanhi2000.github.io/images/ico-wind.svg",background:"rgba(10,10,10,0.2)"})),null,16),s("nav",w,[s("ul",null,[s("li",null,[a(e,{to:"#how-to-create-datetime-extension-methods"},{default:t(()=>n[0]||(n[0]=[o("How to Create DateTime Extension Methods")])),_:1})]),s("li",null,[a(e,{to:"#how-to-chain-same-type-extension-methods"},{default:t(()=>n[1]||(n[1]=[o("How to Chain Same-Type Extension Methods")])),_:1}),s("ul",null,[s("li",null,[a(e,{to:"#how-to-return-the-instance-to-chain"},{default:t(()=>n[2]||(n[2]=[o("How to Return the Instance to Chain")])),_:1})])])]),s("li",null,[a(e,{to:"#why-can-t-i-just-add-these-methods-to-my-class"},{default:t(()=>n[3]||(n[3]=[o("Why Can’t I Just Add These Methods to My Class?")])),_:1})]),s("li",null,[a(e,{to:"#when-to-use-extensions"},{default:t(()=>n[4]||(n[4]=[o("When to Use Extensions")])),_:1}),s("ul",null,[s("li",null,[a(e,{to:"#example-scenario"},{default:t(()=>n[5]||(n[5]=[o("Example Scenario")])),_:1})])])]),s("li",null,[a(e,{to:"#when-not-to-use-extension-methods"},{default:t(()=>n[6]||(n[6]=[o("When Not to Use Extension Methods")])),_:1})]),s("li",null,[a(e,{to:"#things-to-consider-when-designing-extensions"},{default:t(()=>n[7]||(n[7]=[o("Things to Consider When Designing Extensions")])),_:1}),s("ul",null,[s("li",null,[a(e,{to:"#hidden-behavior-confusion"},{default:t(()=>n[8]||(n[8]=[o("Hidden Behavior/Confusion")])),_:1})]),s("li",null,[a(e,{to:"#can-t-access-private-members"},{default:t(()=>n[9]||(n[9]=[o("Can’t Access Private Members")])),_:1})]),s("li",null,[a(e,{to:"#code-duplication-overuse"},{default:t(()=>n[10]||(n[10]=[o("Code Duplication & Overuse")])),_:1})])])]),s("li",null,[a(e,{to:"#conclusion"},{default:t(()=>n[11]||(n[11]=[o("Conclusion")])),_:1})])])]),n[12]||(n[12]=s("hr",null,null,-1)),a(d,{name:"How to Write Extension Methods in C#",desc:"Extension methods are a fundamental part of C# and Object Oriented Programming (OOP). Extension methods in C# allow you to ”extend” existing types, including classes, interfaces, or structs, without modifying their original code. This is particularly...",url:"https://freecodecamp.org/news/how-to-write-extension-methods-in-csharp",logo:"https://cdn.freecodecamp.org/universal/favicons/favicon.ico",preview:"https://cdn.hashnode.com/res/hashnode/image/upload/v1730322390431/42cfe64d-0fce-4f36-a4f7-25e1e56267a4.png"}),n[13]||(n[13]=k(`<p>Extension methods are a fundamental part of C# and Object Oriented Programming (OOP). Extension methods in C# allow you to &quot;extend&quot; existing types, including classes, interfaces, or structs, without modifying their original code.</p><p>This is particularly useful when you want to add new functionality to a type you don&#39;t own or can&#39;t change, like types from third-party libraries or built-in .NET types such as <code>string</code>, <code>List&lt;T&gt;</code>, and so on.</p><p>In this article, you’ll learn how to add extension methods to your classes, as well as third-party and system classes.</p><hr><h2 id="how-to-create-datetime-extension-methods" tabindex="-1"><a class="header-anchor" href="#how-to-create-datetime-extension-methods"><span>How to Create DateTime Extension Methods</span></a></h2><p>Let’s say we want some methods that can be used along with the existing <code>DateTime</code> class, perhaps a method that returns whether the given <code>DateTime</code> object is a weekend or something different.</p><p>Extension methods need to be defined in a static class because they are essentially syntactic sugar that allows you to call a static method as if it were an instance method on the type you&#39;re extending.</p><p>Extension methods need to be in a static class because:</p><ol><li><strong>No Object Needed:</strong> You don’t need to create an object to use an extension method. Since the method adds new functionality to an existing type (like <code>string</code>), it can work without needing an instance of the class.</li><li><strong>Organized Code:</strong> Putting extension methods in a static class keeps things tidy. It allows you to group related methods, and you can easily include them in your code by using the appropriate namespace.</li></ol><p>So, by using a static class, you can add useful methods to existing types without changing their original code, and you don’t need an object to call them.</p><p>First, let’s create a <code>DateTimeExtensions</code> static class.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">class</span> <span class="token class-name">DateTimeExtensions</span> <span class="token punctuation">{</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This will encompass all the <code>DateTime</code> extensions we want to create.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">bool</span></span> <span class="token function">IsWeekend</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">DateTime</span> date<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> date<span class="token punctuation">.</span>DayOfWeek <span class="token keyword">is</span> <span class="token class-name">DayOfWeek<span class="token punctuation">.</span>Saturday</span> <span class="token keyword">or</span> DayOfWeek<span class="token punctuation">.</span>Sunday<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">Explanation:</p><ul><li><code>public static bool IsWeekend</code>: This defines that it is a static method called <code>IsWeekend</code> which will return a <code>bool</code> value (true/false).</li><li><code>this DateTime date</code>: The <code>this</code> keyword as a method argument denotes that this method is an extension method. It means that the method will be an extension of the <code>DateTime</code> class.</li></ul></div><hr><h2 id="how-to-chain-same-type-extension-methods" tabindex="-1"><a class="header-anchor" href="#how-to-chain-same-type-extension-methods"><span>How to Chain Same-Type Extension Methods</span></a></h2><p>For an extension method to be chained with others, it typically needs to return the same type as the one it&#39;s extending (or a compatible type). This allows another method to be called on the result of the previous one.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token keyword">using</span> <span class="token namespace">System<span class="token punctuation">.</span>Globalization</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> <span class="token function">ToTitleCase</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name"><span class="token keyword">string</span></span> str<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> CultureInfo<span class="token punctuation">.</span>CurrentCulture<span class="token punctuation">.</span>TextInfo<span class="token punctuation">.</span><span class="token function">ToTitleCase</span><span class="token punctuation">(</span>str<span class="token punctuation">.</span><span class="token function">ToLower</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> <span class="token function">TrimAndAppend</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name"><span class="token keyword">string</span></span> str<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">string</span></span> toAppend<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> str<span class="token punctuation">.</span><span class="token function">Trim</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> toAppend<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In the above example, both the <code>ToTitleCase</code> and <code>TrimAndAppend</code> methods return a string value, meaning that we can chain the extension methods as below, which will convert the string to title-case before trimming all whitespace and appending the provided string.</p><p>Notice that we only provided the second parameter to the <code>TrimAndAppend</code> method, as the first parameter is the string having the extension method applied to (as explained previously, denoted by the <code>this</code> keyword).</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token class-name"><span class="token keyword">var</span></span> title <span class="token operator">=</span> <span class="token string">&quot;hello world   &quot;</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">ToTitleCase</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">TrimAndAppend</span><span class="token punctuation">(</span><span class="token string">&quot;!!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Output:</span></span>
<span class="line"><span class="token comment">// Hello World!!</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If the extension method returns a different type (not the original one or a compatible type), you cannot chain it. For example:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token class-name"><span class="token keyword">var</span></span> date <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">DateTime</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">date<span class="token punctuation">.</span><span class="token function">IsWeekend</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">AddDays</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>For less obvious reasons, this will not work. When you chain methods, they do not chain from the original variable—they chain from the return type of the previous method call.</p><p>Here, we have a date called <code>IsWeekend()</code> which returns a Boolean. We then attempted to call <code>AddDays(1)</code> on a Boolean value which doesn’t exist, as it is a <code>DateTime</code> extension. The code compiler will fail to build, raising an error informing you of this.</p><h3 id="how-to-return-the-instance-to-chain" tabindex="-1"><a class="header-anchor" href="#how-to-return-the-instance-to-chain"><span>How to Return the Instance to Chain</span></a></h3><p>In some extension methods, especially those for configuration (like Dependency Injection), you return the same instance to allow method chaining. This lets you continue working with the original object or its modified state across multiple calls, enabling a fluent interface.</p><p>Let’s take the example of a list of cars.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name">List<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> <span class="token generic-method"><span class="token function">RemoveDuplicates</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">List<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> list<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Use Distinct to remove duplicates and update the list</span></span>
<span class="line">    list <span class="token operator">=</span> list<span class="token punctuation">.</span><span class="token function">Distinct</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ToList</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Return the modified list to allow method chaining</span></span>
<span class="line">    <span class="token keyword">return</span> list<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name">List<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> <span class="token generic-method"><span class="token function">AddRangeOfItems</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">List<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> list<span class="token punctuation">,</span> <span class="token class-name">IEnumerable<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> items<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Add a range of items to the list</span></span>
<span class="line">    list<span class="token punctuation">.</span><span class="token function">AddRange</span><span class="token punctuation">(</span>items<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Return the modified list to allow method chaining</span></span>
<span class="line">    <span class="token keyword">return</span> list<span class="token punctuation">;</span>  </span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now that we’ve returned the list from these extension methods, we can chain additional methods on the same list. For example, after removing duplicates with <code>RemoveDuplicates()</code>, we can immediately call <code>AddRangeOfItems()</code> on the same list.</p><p>So we can do something like:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token class-name"><span class="token keyword">var</span></span> existingStock <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">List<span class="token punctuation">&lt;</span><span class="token keyword">string</span><span class="token punctuation">&gt;</span></span> <span class="token punctuation">{</span> <span class="token string">&quot;Ford&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Jaguar&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Ferrari&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Ford&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Renault&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name"><span class="token keyword">var</span></span> availableBrands <span class="token operator">=</span> existingStock</span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">RemoveDuplicates</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">AddRangeOfItems</span><span class="token punctuation">(</span><span class="token keyword">new</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span> <span class="token string">&quot;Lamborghini&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// new stock available</span></span>
<span class="line"></span>
<span class="line">Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;Brands Available Now: &quot;</span> <span class="token operator">+</span> <span class="token keyword">string</span><span class="token punctuation">.</span><span class="token function">Join</span><span class="token punctuation">(</span><span class="token string">&quot;, &quot;</span><span class="token punctuation">,</span> availableBrands<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Output: Brands Available Now: Ford, Jaguar, Ferrari, Renault, Lamborghini</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>We removed duplicates from a list of car brands and added new stock to the same list. This works because <code>RemoveDuplicates</code> returns the list, enabling us to chain it with <code>AddRangeOfItems</code>.</p><p>If <code>RemoveDuplicates</code> returned <code>void</code> instead of the list, we wouldn&#39;t be able to chain the methods. It would still remove duplicates, but further actions like adding new stock, wouldn&#39;t be possible in the same expression.</p><p>We’d also have to update the <code>RemoveDuplicates</code> to update the list argument passed in, as <code>Distinct()</code> returns a new list which isn’t being returned as shown below, which I think you’ll agree is a lot more verbose.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token generic-method"><span class="token function">RemoveDuplicates</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">List<span class="token punctuation">&lt;</span>T<span class="token punctuation">&gt;</span></span> list<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Get the distinct elements and clear the original list</span></span>
<span class="line">    <span class="token class-name"><span class="token keyword">var</span></span> distinctItems <span class="token operator">=</span> list<span class="token punctuation">.</span><span class="token function">Distinct</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ToList</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    list<span class="token punctuation">.</span><span class="token function">Clear</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> </span>
<span class="line"></span>
<span class="line">    <span class="token comment">// Add the distinct items back to the original list</span></span>
<span class="line">    list<span class="token punctuation">.</span><span class="token function">AddRange</span><span class="token punctuation">(</span>distinctItems<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="why-can-t-i-just-add-these-methods-to-my-class" tabindex="-1"><a class="header-anchor" href="#why-can-t-i-just-add-these-methods-to-my-class"><span>Why Can’t I Just Add These Methods to My Class?</span></a></h2><p>If the method is not a core part of the class’s functionality, placing it in an extension method can help keep the class focused and maintainable.</p><p><strong>Separation of Concerns</strong>: Using extension methods keeps your code cleaner, and helps reduce complexity**.** It helps avoid bloating the class with methods that may not be used frequently.</p><p><strong>Enhancing External Libraries</strong>: If you’re using a library or framework where you cannot modify the source code, extension methods allow you to add functionality to those types without altering their definitions.</p><p>Let’s say you’re using the <code>FileInfo</code> class from the <code>System.IO</code> namespace to work with files. You may want to add a method to easily check if a file is too large (for example, more than 1 GB), but you cannot modify the <code>FileInfo</code> class directly because it belongs to the System.IO namespace (that is, it&#39;s baked into .Net).</p><p><strong>Without an extension:</strong></p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line"><span class="token class-name"><span class="token keyword">var</span></span> fileInfo <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">FileInfo</span><span class="token punctuation">(</span><span class="token string">&quot;myFile.txt&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>fileInfo<span class="token punctuation">.</span>Length <span class="token operator">&gt;</span> <span class="token number">1024</span> <span class="token operator">*</span> <span class="token number">1024</span> <span class="token operator">*</span> <span class="token number">1024</span><span class="token punctuation">)</span> <span class="token comment">// filesize is bigger than 1GB</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;The file is too large.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;The file size is acceptable.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>With Extension Method:</strong></p><p>You can make this more reusable by adding an extension method that checks whether the file is larger than 1 GB.</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="FileInfoExtensions.cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">class</span> <span class="token class-name">FileInfoExtensions</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">//extension method, with default file size of 1GB (can be overriden)</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">bool</span></span> <span class="token function">IsFileTooLarge</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">FileInfo</span> fileInfo<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">long</span></span> sizeInBytes <span class="token operator">=</span> <span class="token number">1024</span> <span class="token operator">*</span> <span class="token number">1024</span> <span class="token operator">*</span> <span class="token number">1024</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> fileInfo<span class="token punctuation">.</span>Length <span class="token operator">&gt;</span> sizeInBytes<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Now you can use the <code>IsFileTooLarge</code> method directly on <code>FileInfo</code> objects, making your code cleaner:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="cs"><pre><code><span class="line">csharpCopy <span class="token class-name">codevar</span> fileInfo <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">FileInfo</span><span class="token punctuation">(</span><span class="token string">&quot;myFile.txt&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>fileInfo<span class="token punctuation">.</span><span class="token function">IsFileTooLarge</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;The file is too large.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;The file size is acceptable.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Extending third-party libraries and packages can make your code much more compatible.</p><p><strong>Better Organization &amp; Readability</strong>: You can organize extension methods into static classes based on functionality or context, making it easier to find and use them. This is certainly enhanced by allowing extension methods to be chained.</p><hr><h2 id="when-to-use-extensions" tabindex="-1"><a class="header-anchor" href="#when-to-use-extensions"><span>When to Use Extensions</span></a></h2><ul><li><strong>For Utility Methods:</strong> If you have utility methods that are useful for a type but don’t belong directly in the type itself (for example, formatting, validation).</li><li><strong>For Enhancing Built-In Types:</strong> If you want to add functionality to built-in types (like <code>string</code> or <code>DateTime</code>) without modifying them.</li><li><strong>When You Want to Keep Methods Optional:</strong> If you want to provide additional methods that users can opt to use without forcing them to incorporate them into the main class design.</li></ul><h3 id="example-scenario" tabindex="-1"><a class="header-anchor" href="#example-scenario"><span>Example Scenario</span></a></h3><p>Imagine that you have a <code>Person</code> class, and you want to add a method to format the person&#39;s name nicely:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="Person.cs"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Person</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> FirstName <span class="token punctuation">{</span> <span class="token keyword">get</span><span class="token punctuation">;</span> <span class="token keyword">set</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> LastName <span class="token punctuation">{</span> <span class="token keyword">get</span><span class="token punctuation">;</span> <span class="token keyword">set</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Extension method in a static class</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">class</span> <span class="token class-name">PersonExtensions</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> <span class="token function">GetFullName</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">Person</span> person<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token interpolation-string"><span class="token string">$&quot;</span><span class="token interpolation"><span class="token punctuation">{</span><span class="token expression language-csharp">person<span class="token punctuation">.</span>FirstName</span><span class="token punctuation">}</span></span><span class="token string"> </span><span class="token interpolation"><span class="token punctuation">{</span><span class="token expression language-csharp">person<span class="token punctuation">.</span>LastName</span><span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>By using an extension method for <code>GetFullName</code>, you can keep the <code>Person</code> class simple and focused on its core responsibilities, while still providing useful functionality.</p><hr><h2 id="when-not-to-use-extension-methods" tabindex="-1"><a class="header-anchor" href="#when-not-to-use-extension-methods"><span>When Not to Use Extension Methods</span></a></h2><ul><li><strong>For Core Functionality:</strong> If a method is essential to a class&#39;s core behavior, it should be part of the class itself, not an extension.</li><li><strong>For Tight Coupling:</strong> If the extension method requires intimate knowledge of the class&#39;s private state or needs regular access to its internal logic.</li><li><strong>For Public APIs:</strong> When designing a public-facing library or API, it&#39;s often better to include necessary methods directly in the class rather than forcing users to find or create their extension methods.</li></ul><hr><h2 id="things-to-consider-when-designing-extensions" tabindex="-1"><a class="header-anchor" href="#things-to-consider-when-designing-extensions"><span>Things to Consider When Designing Extensions</span></a></h2><p>While extension methods are powerful and convenient in many cases, there are certain cons or situations where using them might not be the best choice:</p><h3 id="hidden-behavior-confusion" tabindex="-1"><a class="header-anchor" href="#hidden-behavior-confusion"><span>Hidden Behavior/Confusion</span></a></h3><ul><li>Extension methods don&#39;t appear directly in the class definition, meaning that they can be harder to discover by developers who are unfamiliar with the available extensions.</li><li>Developers need to know that these extension methods exist, or they might miss using them unless they are working in an IDE with features like IntelliSense (for example, Visual Studio, JetBrains Rider). These IDEs can suggest extension methods from other files or namespaces as they detect the appropriate type. Without a feature-rich IDE, the developer would have to be aware of the extension methods or find the folder they’re stored in.</li></ul><h3 id="can-t-access-private-members" tabindex="-1"><a class="header-anchor" href="#can-t-access-private-members"><span>Can’t Access Private Members</span></a></h3><ul><li>Extension methods can only access members (methods, properties, fields) that are public or internal.</li><li>They cannot access private or protected members of a class because extension methods operate as if they are part of the class from the outside, similar to regular method calls from outside the class.</li></ul><p><strong>Example:</strong></p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="Car"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Car</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">string</span></span> engineNumber <span class="token operator">=</span> <span class="token string">&quot;12345&quot;</span><span class="token punctuation">;</span> <span class="token comment">// Private field</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> Brand <span class="token punctuation">{</span> <span class="token keyword">get</span><span class="token punctuation">;</span> <span class="token keyword">set</span><span class="token punctuation">;</span> <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token string">&quot;Ford&quot;</span><span class="token punctuation">;</span> <span class="token comment">// Public property</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">StartEngine</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// Private method</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;Engine started&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs" data-title="CarExtensions"><pre><code><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">class</span> <span class="token class-name">CarExtensions</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">DisplayBrand</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">Car</span> car<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token interpolation-string"><span class="token string">$&quot;Brand: </span><span class="token interpolation"><span class="token punctuation">{</span><span class="token expression language-csharp">car<span class="token punctuation">.</span>Brand</span><span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Accessing the public &#39;Brand&#39; property</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">TryAccessPrivateField</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">Car</span> car<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// Cannot access the private &#39;engineNumber&#39;</span></span>
<span class="line">        <span class="token comment">// This will result in a compile-time error.</span></span>
<span class="line">        Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>car<span class="token punctuation">.</span>engineNumber<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="code-duplication-overuse" tabindex="-1"><a class="header-anchor" href="#code-duplication-overuse"><span>Code Duplication &amp; Overuse</span></a></h3><ul><li><p>In some cases, extension methods can encourage code duplication. If multiple projects or classes require similar extension methods, you might end up writing or copying the same extension methods in different places, making it harder to manage and update the code consistently.<br>To avoid this, organize your code effectively. I would recommend keeping all extensions within an extensions folder or project, close to the origin (depending on the design patterns being used within your application).</p></li><li><p><strong>Abuse of Extensions:</strong> If used excessively, they can clutter the global space with methods that might not need to be global. This can cause pollution of the type’s API, making it harder to understand what’s core to the class versus what’s added via extensions.<br>In some cases, it&#39;s better to encapsulate functionality in a separate helper classes or services rather than adding it via extension methods.</p></li></ul><hr><h2 id="conclusion" tabindex="-1"><a class="header-anchor" href="#conclusion"><span>Conclusion</span></a></h2><p>Extension methods are useful for adding functionality in a clean and modular way, but they can also introduce confusion, namespace conflicts, and lack of access to private members.</p><p>As highlighted throughout the article, they have many usages and are certainly a very nice feature of the Dotnet framework when used effectively. They should be used when appropriate, but not as a substitute for functionality that belongs within the class itself.</p>`,78)),v(" TODO: add ARTICLE CARD "),a(p,l(c({title:"How to Write Extension Methods in C#",desc:"Extension methods are a fundamental part of C# and Object Oriented Programming (OOP). Extension methods in C# allow you to ”extend” existing types, including classes, interfaces, or structs, without modifying their original code. This is particularly...",link:"https://chanhi2000.github.io/bookshelf/freecodecamp.org/how-to-write-extension-methods-in-csharp.html",logo:"https://cdn.freecodecamp.org/universal/favicons/favicon.ico",background:"rgba(10,10,35,0.2)"})),null,16)])}const I=u(b,[["render",x],["__file","how-to-write-extension-methods-in-csharp.html.vue"]]),E=JSON.parse('{"path":"/freecodecamp.org/how-to-write-extension-methods-in-csharp.html","title":"How to Write Extension Methods in C#","lang":"en-US","frontmatter":{"lang":"en-US","title":"How to Write Extension Methods in C#","description":"Article(s) > How to Write Extension Methods in C#","icon":"iconfont icon-csharp","category":["C#","Article(s)"],"tag":["blog","freecodecamp.org","cs","csharp"],"head":[[{"meta":null},{"property":"og:title","content":"Article(s) > How to Write Extension Methods in C#"},{"property":"og:description","content":"How to Write Extension Methods in C#"},{"property":"og:url","content":"https://chanhi2000.github.io/bookshelf/freecodecamp.org/how-to-write-extension-methods-in-csharp.html"}],["meta",{"property":"og:url","content":"https://chanhi2000.github.io/bookshelf/freecodecamp.org/how-to-write-extension-methods-in-csharp.html"}],["meta",{"property":"og:site_name","content":"📚Bookshelf"}],["meta",{"property":"og:title","content":"How to Write Extension Methods in C#"}],["meta",{"property":"og:description","content":"Article(s) > How to Write Extension Methods in C#"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://cdn.hashnode.com/res/hashnode/image/upload/v1730322390431/42cfe64d-0fce-4f36-a4f7-25e1e56267a4.png"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:src","content":"https://cdn.hashnode.com/res/hashnode/image/upload/v1730322390431/42cfe64d-0fce-4f36-a4f7-25e1e56267a4.png"}],["meta",{"name":"twitter:image:alt","content":"How to Write Extension Methods in C#"}],["meta",{"property":"article:author","content":"Grant Riordan"}],["meta",{"property":"article:tag","content":"blog"}],["meta",{"property":"article:tag","content":"freecodecamp.org"}],["meta",{"property":"article:tag","content":"cs"}],["meta",{"property":"article:tag","content":"csharp"}],["meta",{"property":"article:published_time","content":"2024-10-31T00:00:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"How to Write Extension Methods in C#\\",\\"image\\":[\\"https://cdn.hashnode.com/res/hashnode/image/upload/v1730322390431/42cfe64d-0fce-4f36-a4f7-25e1e56267a4.png\\"],\\"datePublished\\":\\"2024-10-31T00:00:00.000Z\\",\\"dateModified\\":null,\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Grant Riordan\\"}]}"]],"prev":"/programming/cs/articles/README.md","date":"2024-10-31T00:00:00.000Z","isOriginal":false,"author":"Grant Riordan","cover":"https://cdn.hashnode.com/res/hashnode/image/upload/v1730322390431/42cfe64d-0fce-4f36-a4f7-25e1e56267a4.png"},"headers":[{"level":2,"title":"How to Create DateTime Extension Methods","slug":"how-to-create-datetime-extension-methods","link":"#how-to-create-datetime-extension-methods","children":[]},{"level":2,"title":"How to Chain Same-Type Extension Methods","slug":"how-to-chain-same-type-extension-methods","link":"#how-to-chain-same-type-extension-methods","children":[{"level":3,"title":"How to Return the Instance to Chain","slug":"how-to-return-the-instance-to-chain","link":"#how-to-return-the-instance-to-chain","children":[]}]},{"level":2,"title":"Why Can’t I Just Add These Methods to My Class?","slug":"why-can-t-i-just-add-these-methods-to-my-class","link":"#why-can-t-i-just-add-these-methods-to-my-class","children":[]},{"level":2,"title":"When to Use Extensions","slug":"when-to-use-extensions","link":"#when-to-use-extensions","children":[{"level":3,"title":"Example Scenario","slug":"example-scenario","link":"#example-scenario","children":[]}]},{"level":2,"title":"When Not to Use Extension Methods","slug":"when-not-to-use-extension-methods","link":"#when-not-to-use-extension-methods","children":[]},{"level":2,"title":"Things to Consider When Designing Extensions","slug":"things-to-consider-when-designing-extensions","link":"#things-to-consider-when-designing-extensions","children":[{"level":3,"title":"Hidden Behavior/Confusion","slug":"hidden-behavior-confusion","link":"#hidden-behavior-confusion","children":[]},{"level":3,"title":"Can’t Access Private Members","slug":"can-t-access-private-members","link":"#can-t-access-private-members","children":[]},{"level":3,"title":"Code Duplication & Overuse","slug":"code-duplication-overuse","link":"#code-duplication-overuse","children":[]}]},{"level":2,"title":"Conclusion","slug":"conclusion","link":"#conclusion","children":[]}],"git":{"contributors":[{"name":"chanhi2000","email":"chanhi2000@gmail.com","commits":2}]},"readingTime":{"minutes":7.77,"words":2331},"filePathRelative":"freecodecamp.org/how-to-write-extension-methods-in-csharp.md","localizedDate":"October 31, 2024","excerpt":"\\n","copyright":{"author":"Grant Riordan"}}');export{I as comp,E as data};
